import { UmbTextStyles } from "@umbraco-cms/backoffice/style";
import {
  css,
  html,
  customElement,
  state,
  LitElement,
  when,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbWorkspaceViewElement } from "@umbraco-cms/backoffice/workspace";
import { UmbElementMixin } from "@umbraco-cms/backoffice/element-api";
import type { FormDataSource } from "@umbraco-forms/generated";
import { FORMS_DATASOURCE_WORKSPACE_CONTEXT } from "../../datasource-workspace.context-token.js";
import { DateTimeOptions } from "@umbraco-forms/entities";

const elementName = "workspace-view-datasource-info";

@customElement(elementName)
export class UmbWorkspaceViewDataSourceInfoElement
  extends UmbElementMixin(LitElement)
  implements UmbWorkspaceViewElement
{
  @state()
  _dataSource?: FormDataSource;

  #workspaceContext?: typeof FORMS_DATASOURCE_WORKSPACE_CONTEXT.TYPE;

  constructor() {
    super();

    this.consumeContext(FORMS_DATASOURCE_WORKSPACE_CONTEXT, (instance) => {
      this.#workspaceContext = instance;
      this.#observeDataSource();
    });
  }

  #observeDataSource() {
    if (!this.#workspaceContext) return;

    this.observe(this.#workspaceContext.data, (dataSource) => {
      if (!dataSource) return;
      this._dataSource = dataSource;
    });
  }

  render() {
    return html`
      <uui-box headline=${this.localize.term("general_general")}>
        <umb-property-layout label="Id">
          <div slot="editor">${this._dataSource?.unique}</div>
        </umb-property-layout>
        ${when(!this.#workspaceContext?.getIsNew(),
          () => html`
            <umb-property-layout .label=${this.localize.term("content_createDate")}>
              <umb-localize-date
                slot="editor"
                .date=${this._dataSource?.created}
                .options=${DateTimeOptions}
              ></umb-localize-date>
            </umb-property-layout>
            ${when(this._dataSource?.createdBy,
              () => html`
                <umb-property-layout .label=${this.localize.term("content_createBy")}>
                  <div slot="editor">${this._dataSource?.createdByName}</div>
                </umb-property-layout>`)}
            <umb-property-layout .label=${this.localize.term("content_updateDate")}>
              <umb-localize-date
                slot="editor"
                .date=${this._dataSource?.updated}
                .options=${DateTimeOptions}
              ></umb-localize-date>
            </umb-property-layout>
            ${when(this._dataSource?.updatedBy,
              () => html`
                <umb-property-layout .label=${this.localize.term("content_updatedBy")}>
                  <div slot="editor">${this._dataSource?.updatedByName}</div>
                </umb-property-layout>`)}
          `)}
      </uui-box>`;
  }

  static styles = [
    UmbTextStyles,
		css`
			:host {
				display: block;
				padding: var(--uui-size-layout-1);
			}

      uui-box { margin-bottom: 20px }
		`,
  ];
}

export default UmbWorkspaceViewDataSourceInfoElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: UmbWorkspaceViewDataSourceInfoElement;
  }
}
